type Connection_Event (Kind : Event_Kind := None) is record
   Channel : Channel_ID := 0;
   case Kind is
      when None =>
         null;
      when Channel_Open =>
         Open_Sender_Ch     : Channel_ID := 0;
         Open_Init_Window   : Uint32     := 0;
         Open_Max_Pkt       : Uint32     := 0;
         Open_Chan_Type     : String (1 .. 64);
         Open_Chan_Type_Len : Natural    := 0;
         Open_Data          : Byte_Array (1 .. 4_096);
         Open_Data_Len      : Natural    := 0;
      when Channel_Open_Confirm =>
         Confirm_Remote_Ch  : Channel_ID := 0;
         Confirm_Init_Window : Uint32    := 0;
         Confirm_Max_Pkt    : Uint32     := 0;
         Confirm_Data       : Byte_Array (1 .. 4_096);
         Confirm_Data_Len   : Natural    := 0;
      when Channel_Open_Failure =>
         Fail_Reason   : Uint32  := 0;
         Fail_Desc     : String (1 .. 256);
         Fail_Desc_Len : Natural := 0;
         Fail_Lang     : String (1 .. 64);
         Fail_Lang_Len : Natural := 0;
      when Channel_Data =>
         Data_Payload     : Byte_Array (1 .. 35_000);
         Data_Payload_Len : Natural := 0;
      when Channel_Extended_Data =>
         Ext_Data_Type    : Uint32 := 0;
         Ext_Data_Payload : Byte_Array (1 .. 35_000);
         Ext_Data_Len     : Natural := 0;
      when Channel_EOF | Channel_Close =>
         null;
      when Channel_Request =>
         Req_Type       : String (1 .. 64);
         Req_Type_Len   : Natural := 0;
         Req_Want_Reply : Boolean := False;
         Req_Data       : Byte_Array (1 .. 35_000);
         Req_Data_Len   : Natural := 0;
      when Channel_Success | Channel_Failure =>
         null;
      when Global_Request =>
         Glob_Req_Name       : String (1 .. 64);
         Glob_Req_Name_Len   : Natural := 0;
         Glob_Req_Want_Reply : Boolean := False;
         Glob_Req_Data       : Byte_Array (1 .. 4_096);
         Glob_Req_Data_Len   : Natural := 0;
      when Request_Success =>
         Resp_Data   : Byte_Array (1 .. 4_096);
         Resp_Data_Len : Natural := 0;
      when Request_Failure =>
         null;
   end case;
end record;

type Terminal_Mode_Entry is record
   Opcode : Byte;
   Value  : Uint32;
end record;

